import{_ as s,o as a,c as e,ag as n}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"1.3 集合的关系","description":"","frontmatter":{},"headers":[],"relativePath":"notes/gaozhong/gaoyi/chapter01-sets/1-3-集合的关系.md","filePath":"notes/gaozhong/gaoyi/chapter01-sets/1-3-集合的关系.md"}'),$={name:"notes/gaozhong/gaoyi/chapter01-sets/1-3-集合的关系.md"};function o(r,t,p,l,i,d){return a(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="_1-3-集合的关系" tabindex="-1">1.3 集合的关系 <a class="header-anchor" href="#_1-3-集合的关系" aria-label="Permalink to &quot;1.3 集合的关系&quot;">​</a></h1><h2 id="一、子集" tabindex="-1">一、子集 <a class="header-anchor" href="#一、子集" aria-label="Permalink to &quot;一、子集&quot;">​</a></h2><p>若集合 $A$ 中的<strong>每一个</strong>元素都是集合 $B$ 的元素，则称 $A$ 是 $B$ 的<strong>子集</strong>，记作：</p><p>$$A \\subseteq B \\quad \\text{或} \\quad B \\supseteq A$$</p><p>读作：$A$ 包含于 $B$（或 $B$ 包含 $A$）</p><div class="tip custom-block"><p class="custom-block-title">通俗理解</p><p>&quot;小集合&quot;在大集合&quot;里面&quot;。</p></div><details class="details custom-block"><summary>点击展开图示</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ╭───────────────────╮</span></span>\n<span class="line"><span>   ╱        B            ╲</span></span>\n<span class="line"><span>  │   ╭──────────╮       │</span></span>\n<span class="line"><span>  │  ╱    A       ╲      │</span></span>\n<span class="line"><span>  │  │  ● ● ●    │       │</span></span>\n<span class="line"><span>  │  ╲           ╱       │</span></span>\n<span class="line"><span>  │   ╰─────────╯       │</span></span>\n<span class="line"><span>  ╰──────────────────────╯</span></span></code></pre></div><p>$A$ 的所有元素都在 $B$ 内，则 $A \\subseteq B$。</p></details><h2 id="二、真子集" tabindex="-1">二、真子集 <a class="header-anchor" href="#二、真子集" aria-label="Permalink to &quot;二、真子集&quot;">​</a></h2><p>若 $A \\subseteq B$，且 $A \\neq B$，则称 $A$ 是 $B$ 的<strong>真子集</strong>，记作：</p><p>$$A \\subsetneqq B \\quad \\text{或} \\quad B \\supsetneqq A$$</p><div class="tip custom-block"><p class="custom-block-title">子集 vs 真子集</p><ul><li><strong>子集</strong>：$A$ 的元素全在 $B$ 中（$A$ 可以等于 $B$）</li><li><strong>真子集</strong>：$A$ 的元素全在 $B$ 中，且 $A$ 严格小于 $B$</li></ul></div><h2 id="三、空集" tabindex="-1">三、空集 <a class="header-anchor" href="#三、空集" aria-label="Permalink to &quot;三、空集&quot;">​</a></h2><p><strong>空集</strong>：不含有任何元素的集合，记作 $\\varnothing$。</p><div class="warning custom-block"><p class="custom-block-title">重要性质</p><ul><li>空集是<strong>任何集合</strong>的子集：$\\varnothing \\subseteq A$（对任意集合 $A$）</li><li>空集是<strong>任何非空集合</strong>的真子集：$\\varnothing \\subsetneqq A$（$A \\neq \\varnothing$）</li><li>空集本身是自身的子集：$\\varnothing \\subseteq \\varnothing$</li></ul></div><h2 id="四、集合相等" tabindex="-1">四、集合相等 <a class="header-anchor" href="#四、集合相等" aria-label="Permalink to &quot;四、集合相等&quot;">​</a></h2><p>若 $A \\subseteq B$ 且 $B \\subseteq A$，则称 $A$ 与 $B$ <strong>相等</strong>，记作 $A = B$。</p><div class="tip custom-block"><p class="custom-block-title">证明集合相等的方法</p><p>要证 $A = B$，只需证明 $A \\subseteq B$ 且 $B \\subseteq A$。</p></div><h2 id="五、常用结论" tabindex="-1">五、常用结论 <a class="header-anchor" href="#五、常用结论" aria-label="Permalink to &quot;五、常用结论&quot;">​</a></h2><table tabindex="0"><thead><tr><th>结论</th><th>说明</th></tr></thead><tbody><tr><td>$A \\subseteq A$</td><td>集合与自身相等（反身性）</td></tr><tr><td>若 $A \\subseteq B$，$B \\subseteq C$，则 $A \\subseteq C$</td><td>传递性</td></tr><tr><td>$\\varnothing \\subseteq A$</td><td>空集是所有集合的子集</td></tr><tr><td>若 $A \\neq B$，则 $A \\not\\subseteq B$ 或 $B \\not\\subseteq A$</td><td>—</td></tr><tr><td>含 $n$ 个元素的集合，有 $2^n$ 个子集</td><td>包括自身和空集</td></tr></tbody></table><h2 id="六、含-n-个元素的集合" tabindex="-1">六、含 $n$ 个元素的集合 <a class="header-anchor" href="#六、含-n-个元素的集合" aria-label="Permalink to &quot;六、含 $n$ 个元素的集合&quot;">​</a></h2><p>若集合 $A$ 有 $n$ 个元素，则：</p><table tabindex="0"><thead><tr><th>子集类型</th><th>个数</th></tr></thead><tbody><tr><td>子集（含真子集）</td><td>$2^n$</td></tr><tr><td>真子集（非空真子集）</td><td>$2^n - 1$</td></tr><tr><td>非空子集</td><td>$2^n - 1$</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">示例</p><p>集合 ${1, 2, 3}$ 有 $n = 3$ 个元素：</p><ul><li>子集有 $2^3 = 8$ 个：$\\varnothing, {1}, {2}, {3}, {1,2}, {1,3}, {2,3}, {1,2,3}$</li><li>真子集有 $2^3 - 1 = 7$ 个（去掉 ${1,2,3}$ 自身）</li></ul></div><h2 id="七、例题" tabindex="-1">七、例题 <a class="header-anchor" href="#七、例题" aria-label="Permalink to &quot;七、例题&quot;">​</a></h2><details class="details custom-block"><summary>点击查看例题</summary><p><strong>例1：</strong> 判断以下关系是否正确，并说明理由。</p><p>（1）${1, 2} \\subseteq {1, 2, 3}$ （2）${1, 2} \\subsetneqq {1, 2, 3}$ （3）$\\varnothing \\subseteq {1}$ （4）$\\varnothing = {0}$</p><p><strong>解析：</strong></p><p>（1）正确，${1, 2}$ 的所有元素都在 ${1, 2, 3}$ 中。</p><p>（2）正确，且 ${1, 2} \\neq {1, 2, 3}$，所以是真子集。</p><p>（3）正确，空集是所有集合的子集。</p><p>（4）错误，$\\varnothing$ 不含任何元素，${0}$ 含有一个元素 $0$，两者不相等。</p><hr><p><strong>例2：</strong> 已知集合 $A = {x \\mid x^2 = 4}$，$B = {-2, 2}$，判断 $A$ 与 $B$ 的关系。</p><p><strong>解析：</strong></p><p>$A = {x \\mid x^2 = 4} = {-2, 2}$，与 $B$ 的元素完全相同。</p><p>所以 $A = B$，同时也满足 $A \\subseteq B$ 和 $B \\subseteq A$。</p><hr><p><strong>例3：</strong> 集合 ${a, b}$ 有多少个子集？分别写出来。</p><p><strong>解析：</strong></p><p>$n = 2$，子集个数为 $2^2 = 4$ 个：</p><p>$\\varnothing, {a}, {b}, {a, b}$</p></details>',25)])])}const u=s($,[["render",o]]);export{h as __pageData,u as default};
